import{_ as o,o as r,c as t,a4 as a}from"./chunks/framework.Br660gtV.js";const p=JSON.parse('{"title":"Interface: GridFooter · datagrid","description":"","frontmatter":{"title":"Interface: GridFooter · datagrid"},"headers":[],"relativePath":"api/datagrid/interfaces/GridFooter.md","filePath":"api/datagrid/interfaces/GridFooter.md"}'),d={name:"api/datagrid/interfaces/GridFooter.md"};function i(c,e,s,n,l,g){return r(),t("div",null,[...e[0]||(e[0]=[a('<p><a href="./../">@jsvision/datagrid</a> / GridFooter</p><h1 id="interface-gridfooter" tabindex="-1">Interface: GridFooter <a class="header-anchor" href="#interface-gridfooter" aria-label="Permalink to &quot;Interface: GridFooter&quot;">​</a></h1><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/c5f249a6e74f6d31ba8c8be417ce5dcb0b4e1557/packages/datagrid/src/grid-footer.ts#L22" target="_blank" rel="noreferrer">datagrid/src/grid-footer.ts:22</a></p><p>The footer configuration a caller passes to the grid&#39;s <code>footer</code> option: a row of column-aligned aggregates and/or a row of free-form widgets.</p><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;Properties&quot;">​</a></h2><h3 id="aggregates" tabindex="-1">aggregates? <a class="header-anchor" href="#aggregates" aria-label="Permalink to &quot;aggregates?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>aggregates?</strong>: <code>Record</code>&lt;<code>string</code>, <a href="./AggregateSpec.html"><code>AggregateSpec</code></a>&gt;</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/c5f249a6e74f6d31ba8c8be417ce5dcb0b4e1557/packages/datagrid/src/grid-footer.ts#L34" target="_blank" rel="noreferrer">datagrid/src/grid-footer.ts:34</a></p><p>Per-column aggregates, keyed by <code>columnId</code>. Each renders a total aligned under its column, folded over the displayed rows. An entry whose key is not a known column, or whose <code>fn</code> is not a built-in reduction, is ignored (with a dev warning).</p><hr><h3 id="sticky" tabindex="-1">sticky? <a class="header-anchor" href="#sticky" aria-label="Permalink to &quot;sticky?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>sticky?</strong>: <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/c5f249a6e74f6d31ba8c8be417ce5dcb0b4e1557/packages/datagrid/src/grid-footer.ts#L28" target="_blank" rel="noreferrer">datagrid/src/grid-footer.ts:28</a></p><p>Keep the footer visible while the body scrolls. Defaults to <code>true</code>; v1 footers are always sticky (the fixed-band layout gives it for free), so a <code>false</code> here is reserved — it is treated as <code>true</code> with a dev warning until a non-sticky/inline footer ships.</p><hr><h3 id="widgets" tabindex="-1">widgets? <a class="header-anchor" href="#widgets" aria-label="Permalink to &quot;widgets?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>widgets?</strong>: readonly <code>View</code>[]</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/c5f249a6e74f6d31ba8c8be417ce5dcb0b4e1557/packages/datagrid/src/grid-footer.ts#L39" target="_blank" rel="noreferrer">datagrid/src/grid-footer.ts:39</a></p><p>A free-form widget row — any <code>View</code>s (totals <code>Text</code>, command <code>Button</code>s, the reactive &quot;N of M&quot; and selection-count read-outs), laid out in a flow row spanning the footer band.</p>',19)])])}const h=o(d,[["render",i]]);export{p as __pageData,h as default};
